import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getAnalysisById } from '../services/resume';
import Card from '../components/UI/Card';
import Button from '../components/UI/Button';
import { 
  ArrowLeftIcon, 
  ArrowPathIcon,
  ChartBarIcon,
  CheckCircleIcon,
  XCircleIcon,
  LightBulbIcon,
  DocumentTextIcon,
  ShareIcon,
  PrinterIcon
} from '@heroicons/react/24/outline';

const Result = () => {
  const { id } = useParams();
  const [analysis, setAnalysis] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadAnalysis();
  }, [id]);

  const loadAnalysis = async () => {
    try {
      const data = await getAnalysisById(id);
      setAnalysis(data);
    } catch (error) {
      console.error('Failed to load analysis:', error);
    } finally {
      setLoading(false);
    }
  };

  const getScoreColor = (score) => {
    if (score >= 80) return 'text-green-600';
    if (score >= 60) return 'text-yellow-600';
    if (score >= 40) return 'text-orange-600';
    return 'text-red-600';
  };

  const getScoreMessage = (score) => {
    if (score >= 80) return 'Excellent! Your resume is well-optimized.';
    if (score >= 60) return 'Good, but there\'s room for improvement.';
    if (score >= 40) return 'Needs improvement.';
    return 'Needs significant improvement.';
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <ArrowPathIcon className="h-12 w-12 text-indigo-600 animate-spin mx-auto mb-4" />
          <p className="text-gray-600">Loading analysis results...</p>
        </div>
      </div>
    );
  }

  if (!analysis) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Card className="text-center max-w-md">
          <DocumentTextIcon className="h-16 w-16 text-gray-400 mx-auto mb-4" />
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Analysis Not Found</h2>
          <p className="text-gray-500 mb-6">The analysis you're looking for doesn't exist or has been removed.</p>
          <Link to="/">
            <Button variant="primary">Go to Dashboard</Button>
          </Link>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="mb-8">
          <Link to="/" className="inline-flex items-center text-gray-500 hover:text-gray-700 mb-4">
            <ArrowLeftIcon className="h-4 w-4 mr-1" />
            Back to Dashboard
          </Link>
          <div className="flex items-center justify-between flex-wrap gap-4">
            <div>
              <h1 className="text-3xl font-bold bg-gradient-to-r from-indigo-600 to-purple-600 bg-clip-text text-transparent">
                Analysis Result
              </h1>
              <p className="text-gray-600 mt-1">
                Here's how you stack up against the role
              </p>
            </div>
            <div className="flex space-x-2">
              <Button variant="secondary" size="sm" icon={<PrinterIcon className="h-4 w-4" />}>
                Print
              </Button>
              <Button variant="secondary" size="sm" icon={<ShareIcon className="h-4 w-4" />}>
                Share
              </Button>
            </div>
          </div>
        </div>

        {/* Score Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <Card>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-gray-900">ATS Score</h3>
              <ChartBarIcon className="h-6 w-6 text-gray-400" />
            </div>
            <div>
              <div className="flex items-end justify-between mb-2">
                <span className="text-sm font-medium text-gray-500">Overall Resume Optimization</span>
                <span className={`text-3xl font-bold ${getScoreColor(analysis.atsScore)}`}>
                  {analysis.atsScore}%
                </span>
              </div>
              <div className="w-full h-3 bg-gray-200 rounded-full overflow-hidden mb-2">
                <div 
                  className={`h-full rounded-full transition-all duration-1000 ${
                    analysis.atsScore >= 80 ? 'bg-green-500' :
                    analysis.atsScore >= 60 ? 'bg-yellow-500' :
                    analysis.atsScore >= 40 ? 'bg-orange-500' : 'bg-red-500'
                  }`}
                  style={{ width: `${analysis.atsScore}%` }}
                />
              </div>
              <p className="text-sm text-gray-600 mt-2">{getScoreMessage(analysis.atsScore)}</p>
            </div>
          </Card>

          <Card>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-gray-900">Skills Match</h3>
              <CheckCircleIcon className="h-6 w-6 text-gray-400" />
            </div>
            <div>
              <div className="flex items-end justify-between mb-2">
                <span className="text-sm font-medium text-gray-500">Alignment with Job Requirements</span>
                <span className={`text-3xl font-bold ${getScoreColor(analysis.matchPercentage)}`}>
                  {analysis.matchPercentage}%
                </span>
              </div>
              <div className="w-full h-3 bg-gray-200 rounded-full overflow-hidden mb-2">
                <div 
                  className="h-full rounded-full bg-indigo-500 transition-all duration-1000"
                  style={{ width: `${analysis.matchPercentage}%` }}
                />
              </div>
              <p className="text-sm text-gray-600 mt-2">
                {analysis.matchPercentage >= 70 ? 'Strong match!' : 'Consider adding more relevant skills.'}
              </p>
            </div>
          </Card>
        </div>

        {/* Skills Section */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <Card>
            <div className="flex items-center space-x-2 mb-4">
              <CheckCircleIcon className="h-5 w-5 text-green-500" />
              <h3 className="text-lg font-semibold text-gray-900">
                Skills Found ({analysis.foundSkills?.length || 0})
              </h3>
            </div>
            <div className="flex flex-wrap gap-2 max-h-64 overflow-y-auto">
              {analysis.foundSkills?.map((skill, index) => (
                <span
                  key={index}
                  className="px-3 py-1.5 bg-green-100 text-green-800 rounded-full text-sm font-medium hover:bg-green-200 transition-colors"
                >
                  {skill}
                </span>
              ))}
              {(!analysis.foundSkills || analysis.foundSkills.length === 0) && (
                <p className="text-gray-500 text-center w-full py-8">No matching skills found</p>
              )}
            </div>
          </Card>

          <Card>
            <div className="flex items-center space-x-2 mb-4">
              <XCircleIcon className="h-5 w-5 text-red-500" />
              <h3 className="text-lg font-semibold text-gray-900">
                Missing Skills ({analysis.missingSkills?.length || 0})
              </h3>
            </div>
            <div className="flex flex-wrap gap-2 max-h-64 overflow-y-auto">
              {analysis.missingSkills?.map((skill, index) => (
                <span
                  key={index}
                  className="px-3 py-1.5 bg-red-100 text-red-800 rounded-full text-sm font-medium hover:bg-red-200 transition-colors"
                >
                  {skill}
                </span>
              ))}
              {(!analysis.missingSkills || analysis.missingSkills.length === 0) && (
                <p className="text-green-600 text-center w-full py-8">Great job! No missing skills!</p>
              )}
            </div>
          </Card>
        </div>

        {/* Suggestions */}
        <Card className="mb-8">
          <div className="flex items-center space-x-2 mb-4">
            <LightBulbIcon className="h-5 w-5 text-yellow-500" />
            <h3 className="text-lg font-semibold text-gray-900">
              Improvement Suggestions ({analysis.suggestions?.length || 0})
            </h3>
          </div>
          {analysis.suggestions?.length > 0 ? (
            <ul className="space-y-3">
              {analysis.suggestions.map((suggestion, index) => (
                <li key={index} className="flex items-start p-3 bg-yellow-50 rounded-lg">
                  <span className="inline-flex items-center justify-center w-6 h-6 bg-yellow-100 text-yellow-800 rounded-full text-sm font-medium mr-3 flex-shrink-0">
                    {index + 1}
                  </span>
                  <span className="text-gray-700">{suggestion}</span>
                </li>
              ))}
            </ul>
          ) : (
            <p className="text-gray-500 text-center py-8">No suggestions - Your resume looks great!</p>
          )}
        </Card>

        {/* Quick Stats */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
          <Card className="text-center">
            <p className="text-sm text-gray-500 mb-1">Found Skills</p>
            <p className="text-4xl font-bold text-indigo-600">{analysis.foundSkills?.length || 0}</p>
          </Card>
          <Card className="text-center">
            <p className="text-sm text-gray-500 mb-1">Missing Skills</p>
            <p className="text-4xl font-bold text-red-600">{analysis.missingSkills?.length || 0}</p>
          </Card>
          <Card className="text-center">
            <p className="text-sm text-gray-500 mb-1">Suggestions</p>
            <p className="text-4xl font-bold text-yellow-600">{analysis.suggestions?.length || 0}</p>
          </Card>
        </div>

        {/* Action Buttons */}
        <div className="flex justify-center space-x-4">
          <Link to="/analyze">
            <Button variant="primary" size="lg" icon={<DocumentTextIcon className="h-5 w-5" />}>
              New Analysis
            </Button>
          </Link>
        </div>
      </div>
    </div>
  );
};

export default Result;
